import * as child_process from "node:child_process";
import * as crypto from "node:crypto";
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { getLanguageConfig, sanitizeEnvironment } from "./languages.ts";

export interface SandboxResult {
	stdout: string;
	stderr: string;
	exitCode: number;
 timedOut: boolean;
	bytesProcessed: number;
	bytesReturned: number;
}

export interface SandboxOptions {
	language: string;
	code: string;
	cwd: string;
	timeout?: number;
	maxOutputBytes?: number;
	allowNetwork?: boolean;
}

const DEFAULT_TIMEOUT = 30000;
const DEFAULT_MAX_OUTPUT = 5120;

export async function executeInSandbox(options: SandboxOptions): Promise<SandboxResult> {
	const langConfig = getLanguageConfig(options.language);
	if (!langConfig) {
		return {
			stdout: "",
			stderr: `Unsupported language: ${options.language}. Supported: javascript, typescript, python, shell`,
			exitCode: 1,
			timedOut: false,
			bytesProcessed: 0,
			bytesReturned: 0,
		};
	}

	const timeout = options.timeout ?? DEFAULT_TIMEOUT;
	const maxOutputBytes = options.maxOutputBytes ?? DEFAULT_MAX_OUTPUT;

	// Write code to temp file
	const tmpDir = os.tmpdir();
	const randomId = crypto.randomBytes(8).toString("hex");
	const filename = path.join(tmpDir, `pi-smart-${process.pid}-${randomId}.${langConfig.extension}`);

	try {
		fs.writeFileSync(filename, options.code, "utf-8");

		const command = langConfig.command[0]!;
		const args = [...langConfig.command.slice(1), ...langConfig.argsTemplate(filename)];
		const cleanEnv = sanitizeEnvironment(process.env, langConfig);

		// Block network by removing proxy vars and setting restrictive env
		if (!options.allowNetwork) {
			delete cleanEnv.HTTP_PROXY;
			delete cleanEnv.HTTPS_PROXY;
			delete cleanEnv.http_proxy;
			delete cleanEnv.https_proxy;
			delete cleanEnv.ALL_PROXY;
			delete cleanEnv.all_proxy;
		}

		const result = child_process.spawnSync(command, args, {
			cwd: options.cwd,
			env: cleanEnv,
			timeout,
			maxBuffer: 10 * 1024 * 1024, // 10MB
			encoding: "utf-8",
			killSignal: "SIGKILL",
		});

		const stdout = (result.stdout as string) ?? "";
		const stderr = (result.stderr as string) ?? "";
		const exitCode = result.status ?? 1;
		const timedOut = result.signal === "SIGKILL" || result.error?.message?.includes("ETIMEDOUT") === true;

		// Output gating
		const bytesProcessed = Buffer.byteLength(stdout, "utf-8");
		let output = stdout;

		if (bytesProcessed > maxOutputBytes) {
			// Truncate: first 2KB + marker + last 2KB
			const firstPart = stdout.slice(0, 2048);
			const lastPart = stdout.slice(-2048);
			output = `${firstPart}\n[... ${(bytesProcessed - 4096)} bytes truncated ...]\n${lastPart}`;
		}

		const bytesReturned = Buffer.byteLength(output, "utf-8");

		return {
			stdout: output,
			stderr,
			exitCode,
			timedOut,
			bytesProcessed,
			bytesReturned,
		};
	} finally {
		// Clean up temp file
		try {
			fs.unlinkSync(filename);
		} catch {
			// Best effort cleanup
		}
	}
}

export interface Filter {
	name: string;
	apply(text: string): string;
}

export interface PipelineMetrics {
	bytesIn: number;
	bytesOut: number;
	reductionPct: number;
	filtersApplied: number;
}

export function applyPipeline(text: string, filters: Filter[]): { result: string; metrics: PipelineMetrics } {
	const bytesIn = Buffer.byteLength(text, "utf-8");
	let result = text;
	let filtersApplied = 0;

	for (const filter of filters) {
		try {
			const before = result;
			result = filter.apply(result);
			if (result !== before) filtersApplied++;
		} catch (error: unknown) {
			// SAFETY: If filter fails, skip it (rtk fallback pattern)
			console.error(`[pi-smart] filter "${filter.name}" error: ${error instanceof Error ? error.message : String(error)}`);
			continue;
		}
	}

	const bytesOut = Buffer.byteLength(result, "utf-8");
	const reductionPct = bytesIn > 0 ? Math.round(((bytesIn - bytesOut) / bytesIn) * 100) : 0;

	return {
		result,
		metrics: { bytesIn, bytesOut, reductionPct, filtersApplied },
	};
}

import type { Intensity } from "../config.ts";

export interface CompressionResult {
	text: string;
	tokensBefore: ***;
	tokensAfter: ***;
	reductionPct: number;
}

// Filler phrases to remove in terse/normal mode
const FILLER_PHRASES = [
	"I think ",
	"It seems like ",
	"You might want to ",
	"The reason is that ",
	"In my opinion, ",
	"I would say ",
	"Let me explain ",
	"Here's the thing: ",
	"Basically, ",
	"Essentially, ",
	"To be honest, ",
	"As far as I can tell, ",
];

const PLEASANTRY_LINES = [
	"Sure!",
	"Great question!",
	"Hope this helps!",
	"Happy to help!",
	"Let me know if you need anything else!",
	"Does that make sense?",
	"Good question!",
];

/**
 * Estimate token count (rough: ~4 chars per token)
 */
function estimateTokens(text: string): number {
	return Math.ceil(text.length / 4);
}

/**
 * Check if a line is inside a code block
 */
function isInsideCodeBlock(lines: string[], lineIdx: number): boolean {
	let count = 0;
	for (let i = 0; i <= lineIdx; i++) {
		if (lines[i]!.trimStart().startsWith("```")) count++;
	}
	return count % 2 === 1;
}

/**
 * Apply caveman compression — keep only code, identifiers, paths, commands, errors
 */
export function cavemanCompress(text: string): CompressionResult {
	const tokensBefore = ***;
	const lines = text.split("\n");
	const result: string[] = [];

	for (let i = 0; i < lines.length; i++) {
		const line = lines[i]!;

		// Always keep code blocks, list items, paths, commands
		if (isInsideCodeBlock(lines, i)) {
			result.push(line);
			continue;
		}

		// Keep lines with code-like content (backticks, paths, commands)
		if (/`/.test(line) || /\/[\w.-]+/.test(line) || /^\s*\$\s/.test(line) || /^\s*[-*]\s/.test(line)) {
			result.push(stripFiller(line));
			continue;
		}

		// Keep empty lines
		if (line.trim() === "") {
			// Collapse consecutive blank lines
			if (result.length > 0 && result[result.length - 1]!.trim() !== "") {
				result.push(line);
			}
			continue;
		}

		// For prose lines, strip filler and keep if meaningful
		const stripped = stripFiller(line);
		if (stripped.trim().length > 0) {
			result.push(stripped);
		}
	}

	const output = result.join("\n");
	const tokensAfter = ***;
	const reductionPct = tokensBefore > 0 ? Math.round(((tokensBefore - tokensAfter) / tokensBefore) * 100) : 0;

	return { text: output, tokensBefore, tokensAfter, reductionPct };
}

function stripFiller(line: string): string {
	let result = line;
	for (const phrase of FILLER_PHRASES) {
		result = result.replace(phrase, "");
	}
	// Remove pleasantries at line start
	for (const pleasantry of PLEASANTRY_LINES) {
		if (result.trim() === pleasantry) return "";
		if (result.trimStart().startsWith(pleasantry + " ")) {
			result = result.slice(result.indexOf(pleasantry) + pleasantry.length + 1);
		}
	}
	return result;
}

/**
 * Apply light compression for normal mode — remove pleasantries only
 */
export function lightCompress(text: string): CompressionResult {
	const tokensBefore = ***;
	const lines = text.split("\n");
	const result: string[] = [];

	for (let i = 0; i < lines.length; i++) {
		const line = lines[i]!;
		if (isInsideCodeBlock(lines, i)) {
			result.push(line);
			continue;
		}
		const isPleasantry = PLEASANTRY_LINES.some((p) => line.trim() === p);
		if (!isPleasantry) {
			result.push(line);
		}
	}

	const output = result.join("\n");
	const tokensAfter = ***;
	const reductionPct = tokensBefore > 0 ? Math.round(((tokensBefore - tokensAfter) / tokensBefore) * 100) : 0;

	return { text: output, tokensBefore, tokensAfter, reductionPct };
}

/**
 * Apply compression based on intensity level
 */
export function compressByIntensity(text: string, intensity: Intensity): CompressionResult {
	switch (intensity) {
		case "terse":
			return cavemanCompress(text);
		case "normal":
			return lightCompress(text);
		case "verbose":
			return { text, tokensBefore: ***, tokensAfter: ***, reductionPct: 0 };
	}
}

import * as fs from "node:fs";
import * as path from "node:path";
import BetterSqlite3 from "better-sqlite3";
import type Database from "better-sqlite3";
import { initSchema } from "./schema.ts";

/**
 * Manages the SQLite database connection for pi-memory.
 * Database is stored at <cwd>/.pi-memory/memory.db.
 */
export class MemoryDB {
	public readonly cwd: string;
	public readonly dbPath: string;
	private db: Database.Database | null = null;

	constructor(cwd: string) {
		this.cwd = cwd;
		const dir = path.join(cwd, ".pi-memory");
		fs.mkdirSync(dir, { recursive: true });
		this.dbPath = path.join(dir, "memory.db");
	}

	/** Open (or return existing) database connection with full schema. */
	open(): Database.Database {
		if (this.db) return this.db;
		this.db = new BetterSqlite3(this.dbPath) as unknown as Database.Database;
		initSchema(this.db);
		return this.db;
	}

	/** Get the current open connection (throws if not open). */
	getConnection(): Database.Database {
		if (!this.db) throw new Error("MemoryDB not opened. Call open() first.");
		return this.db;
	}

	/** Close the database connection. */
	close(): void {
		if (this.db) {
			try {
				this.db.close();
			} catch {
				// Ignore close errors
			}
			this.db = null;
		}
	}

	/** Check if the database is currently open. */
	get isOpen(): boolean {
		return this.db !== null;
	}
}

