import type { PlanModeState, Plan, PlanTask, PipelineState } from "../types.ts";

/** Valid state transitions for the plan mode state machine. */
const TRANSITIONS: Record<PlanModeState, PlanModeState[]> = {
	"IDLE": ["GATHERING"],
	"GATHERING": ["SPEC'ING", "IDLE"],
	"SPEC'ING": ["PLANNING", "GATHERING"],
	"PLANNING": ["READY", "SPEC'ING"],
	"READY": ["EXECUTING", "PLANNING"],
	"EXECUTING": ["REVIEWING", "READY"],
	"REVIEWING": ["COMPLETE", "EXECUTING"],
	"COMPLETE": ["IDLE"],
};

/**
 * Check if a transition from `from` to `to` is valid.
 */
export function canTransition(from: PlanModeState, to: PlanModeState): boolean {
	return TRANSITIONS[from]?.includes(to) ?? false;
}

/**
 * Attempt a state transition. Returns the new state on success, or throws.
 */
export function transition(state: PipelineState, to: PlanModeState): PipelineState {
	if (!canTransition(state.mode, to)) {
		throw new Error(`Invalid state transition: ${state.mode} → ${to}`);
	}
	return { ...state, mode: to };
}

/**
 * Create a new plan with empty tasks in the GATHERING state.
 */
export function createPlan(title: string): Plan {
	return {
		title,
		spec: "",
		tasks: [],
		issues: [],
		createdAt: new Date().toISOString(),
		state: "GATHERING",
	};
}

/**
 * Get the ordered tasks from a plan (sorted by dependency).
 */
export function orderedTasks(plan: Plan): PlanTask[] {
	return [...plan.tasks].sort((a, b) => {
		// If a depends on b, a comes after
		if (a.depends_on.includes(b.id)) return 1;
		// If b depends on a, b comes after
		if (b.depends_on.includes(a.id)) return -1;
		return 0;
	});
}

/**
 * Get the status string for the current plan state.
 */
export function planStatus(state: PipelineState): string {
	const lines: string[] = [];
	lines.push(`State: ${state.mode}`);
	if (state.plan) {
		lines.push(`Plan: ${state.plan.title}`);
		lines.push(`Tasks: ${state.plan.tasks.length}`);
		const completed = state.currentTaskIndex;
		lines.push(`Progress: ${completed}/${state.plan.tasks.length}`);
		if (state.plan.issues.length > 0) {
			lines.push(`Issues: ${state.plan.issues.join(", ")}`);
		}
	}
	lines.push(`Complexity: ${state.complexity}`);
	lines.push(`Ambiguity: ${state.ambiguityScore.toFixed(2)}`);
	return lines.join("\n");
}

import type { Connection, ConnectionEvents } from "./connection.ts";
import { Lifecycle } from "./lifecycle.ts";
import type {
	DAPCapabilities,
	SessionState,
	StoppedEvent,
	Thread,
	Source,
} from "../types.ts";

export interface SessionOptions {
	sessionId: string;
	program: string;
	args?: string[];
	env?: Record<string, string>;
	stopOnEntry?: boolean;
	cwd?: string;
	adapterId?: string;
	timeout?: number;
}

export type SessionEventHandler = (event: string, data: unknown) => void;

/**
 * Represents a single debug session.
 * Wraps Connection + Lifecycle, tracks threads and stopped state.
 */
export class Session {
	readonly sessionId: string;
	private connection: Connection;
	private lifecycle: Lifecycle;
	private threads = new Map<number, Thread>();
	private _state: SessionState = "terminated";
	private _stoppedReason: string | null = null;
	private _stoppedThreadId: number | null = null;
	private eventHandler: SessionEventHandler;

	constructor(
		sessionId: string,
		connection: Connection,
		eventHandler: SessionEventHandler,
		timeout = 30000,
	) {
		this.sessionId = sessionId;
		this.connection = connection;
		this.eventHandler = eventHandler;

		this.lifecycle = new Lifecycle(
			connection,
			{
				onStateChanged: (state) => {
					this._state = state;
				},
			},
			timeout,
		);
	}

	get state(): SessionState {
		return this._state;
	}

	get stoppedReason(): string | null {
		return this._stoppedReason;
	}

	get stoppedThreadId(): number | null {
		return this._stoppedThreadId;
	}

	get capabilities(): DAPCapabilities {
		return this.lifecycle.getCapabilities();
	}

	get isConnected(): boolean {
		return !this.connection.isClosed;
	}

	/** Send a raw DAP request through the connection. */
	sendRequest(method: string, params?: Record<string, unknown>): Promise<Record<string, unknown>> {
		return this.connection.sendRequest(method, params);
	}

	/** Send a raw DAP notification through the connection. */
	sendNotification(method: string, params?: Record<string, unknown>): void {
		this.connection.sendNotification(method, params);
	}

	/** Initialize and launch the debug session. */
	async start(options: Omit<SessionOptions, "sessionId">): Promise<DAPCapabilities> {
		const caps = await this.lifecycle.initialize("pi-debug", options.adapterId ?? "pi-debug");
		await this.lifecycle.launch(options.program, {
			args: options.args,
			env: options.env,
			stopOnEntry: options.stopOnEntry,
			cwd: options.cwd,
		});
		await this.lifecycle.configurationDone();
		return caps;
	}

	/** Attach to a running process. */
	async attach(options: {
		program?: string;
		pid?: string | number;
		port?: number;
		host?: string;
		adapterId?: string;
	}): Promise<DAPCapabilities> {
		const caps = await this.lifecycle.initialize("pi-debug", options.adapterId ?? "pi-debug");
		await this.lifecycle.attach({
			program: options.program,
			pid: options.pid,
			port: options.port,
			host: options.host,
		});
		await this.lifecycle.configurationDone();
		return caps;
	}

	/** Stop the debug session. */
	async stop(): Promise<void> {
		await this.lifecycle.disconnect(true);
		this.connection.kill();
	}

	/** Handle a DAP event from the connection. */
	handleEvent(method: string, params: Record<string, unknown>): void {
		switch (method) {
			case "stopped": {
				const stopped = params as unknown as StoppedEvent;
				this._state = "stopped";
				this._stoppedReason = stopped.reason;
				this._stoppedThreadId = stopped.threadId ?? null;
				break;
			}
			case "continued": {
				this._state = "running";
				this._stoppedReason = null;
				this._stoppedThreadId = null;
				break;
			}
			case "terminated": {
				this._state = "terminated";
				break;
			}
			case "thread": {
				const threadData = params as { reason: string; threadId: number };
				if (threadData.reason === "started") {
					this.threads.set(threadData.threadId, {
						id: threadData.threadId,
						name: `Thread ${threadData.threadId}`,
					});
				} else {
					this.threads.delete(threadData.threadId);
				}
				break;
			}
		}
		this.eventHandler(method, params);
	}

	/** Get a thread ID for stepping. Falls back to first known thread or 1. */
	getDefaultThreadId(): number {
		if (this._stoppedThreadId !== null) return this._stoppedThreadId;
		const first = this.threads.keys().next();
		if (!first.done) return first.value;
		return 1;
	}
}

import { ChildProcess, spawn } from "node:child_process";
import { createConnection as createTcpConnection, Socket } from "node:net";
import type { DAPRequest, DAPResponse, DAPNotification, DAPMessage } from "../types.ts";

export interface ConnectionEvents {
	onResponse: (msg: DAPResponse) => void;
	onEvent: (method: string, params: Record<string, unknown>) => void;
	onError: (error: Error) => void;
	onClose: () => void;
}

/**
 * DAP transport supporting both stdio (Content-Length framing) and TCP.
 * DAP uses the same Content-Length framing as LSP over stdio.
 */
export class Connection {
	private proc: ChildProcess | null = null;
	private socket: Socket | null = null;
	private buffer = "";
	private nextId = 1;
	private pending = new Map<number, { resolve: (value: Record<string, unknown>) => void; reject: (error: Error) => void }>();
	private handlers: ConnectionEvents;
	private closed = false;
	private transport: "stdio" | "tcp" = "stdio";

	constructor(handlers: ConnectionEvents) {
		this.handlers = handlers;
	}

	get isClosed(): boolean {
		return this.closed;
	}

	get transportType(): "stdio" | "tcp" {
		return this.transport;
	}

	/** Start a stdio-based debug adapter as a child process. */
	startStdio(command: string[], cwd: string, env?: Record<string, string>): void {
		this.transport = "stdio";
		this.proc = spawn(command[0], command.slice(1), {
			cwd,
			stdio: ["pipe", "pipe", "pipe"],
			env: { ...process.env, ...env },
		});

		this.proc.stdout?.on("data", (chunk: Buffer) => {
			this.buffer += chunk.toString("utf-8");
			this.parseMessages();
		});

		this.proc.stderr?.on("data", (chunk: Buffer) => {
			// Debug adapters log to stderr; ignore or forward
			void chunk;
		});

		this.proc.on("error", (err) => {
			this.handlers.onError(err);
		});

		this.proc.on("close", () => {
			this.handleClose();
		});
	}

	/** Connect to a TCP-based debug adapter. */
	connectTcp(host: string, port: number): Promise<void> {
		this.transport = "tcp";
		return new Promise((resolve, reject) => {
			this.socket = createTcpConnection({ host, port }, () => {
				resolve();
			});

			this.socket.on("data", (chunk: Buffer) => {
				this.buffer += chunk.toString("utf-8");
				this.parseMessages();
			});

			this.socket.on("error", (err) => {
				this.handlers.onError(err);
				reject(err);
			});

			this.socket.on("close", () => {
				this.handleClose();
			});
		});
	}

	/** Send a DAP request and return a promise for the result. */
	sendRequest(method: string, params?: Record<string, unknown>): Promise<Record<string, unknown>> {
		return new Promise((resolve, reject) => {
			if (this.closed) {
				reject(new Error("Connection is closed"));
				return;
			}

			const id = this.nextId++;
			const msg: DAPRequest = { jsonrpc: "2.0", id, method, params };
			this.pending.set(id, { resolve, reject });
			this.write(msg);
		});
	}

	/** Send a DAP notification (no response expected). */
	sendNotification(method: string, params?: Record<string, unknown>): void {
		if (this.closed) return;
		const msg: DAPNotification = { jsonrpc: "2.0", method, params };
		this.write(msg);
	}

	private write(msg: DAPRequest | DAPNotification): void {
		const body = JSON.stringify(msg);
		const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
		const data = header + body;

		if (this.transport === "stdio" && this.proc?.stdin?.writable) {
			this.proc.stdin.write(data, "utf-8");
		} else if (this.transport === "tcp" && this.socket?.writable) {
			this.socket.write(data, "utf-8");
		}
	}

	private handleClose(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection closed"));
		}
		this.pending.clear();
		this.handlers.onClose();
	}

	private parseMessages(): void {
		while (this.buffer.length > 0) {
			const headerEnd = this.buffer.indexOf("\r\n\r\n");
			if (headerEnd === -1) break;

			const header = this.buffer.substring(0, headerEnd);
			const match = header.match(/^Content-Length:\s*(\d+)/i);
			if (!match) {
				this.buffer = this.buffer.substring(headerEnd + 4);
				continue;
			}

			const contentLength = Number.parseInt(match[1], 10);
			const bodyStart = headerEnd + 4;
			const bodyEnd = bodyStart + contentLength;

			if (this.buffer.length < bodyEnd) break;

			const body = this.buffer.substring(bodyStart, bodyEnd);
			this.buffer = this.buffer.substring(bodyEnd);

			try {
				const msg = JSON.parse(body) as DAPMessage;
				this.handleMessage(msg);
			} catch {
				// Ignore malformed messages
			}
		}
	}

	private handleMessage(msg: DAPMessage): void {
		if ("id" in msg && ("result" in msg || "error" in msg)) {
			// Response
			const resp = msg as DAPResponse;
			const pending = this.pending.get(resp.id);
			if (pending) {
				this.pending.delete(resp.id);
				if ("error" in resp) {
					pending.reject(new Error(`DAP error ${resp.error.code}: ${resp.error.message}`));
				} else {
					pending.resolve(resp.result);
				}
			}
			this.handlers.onResponse(resp);
		} else if ("method" in msg) {
			// Notification / event
			const notif = msg as DAPNotification;
			this.handlers.onEvent(notif.method, notif.params ?? {});
		}
	}

	/** Kill the connection and clean up. */
	kill(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection killed"));
		}
		this.pending.clear();
		this.proc?.kill();
		this.proc = null;
		this.socket?.destroy();
		this.socket = null;
	}
}

/** Parse Content-Length framed messages from a raw buffer string. Returns parsed messages and remaining buffer. */
export function parseMessages(raw: string): { messages: DAPMessage[]; remaining: string } {
	const messages: DAPMessage[] = [];
	let buffer = raw;

	while (buffer.length > 0) {
		const headerEnd = buffer.indexOf("\r\n\r\n");
		if (headerEnd === -1) break;

		const header = buffer.substring(0, headerEnd);
		const match = header.match(/^Content-Length:\s*(\d+)/i);
		if (!match) {
			buffer = buffer.substring(headerEnd + 4);
			continue;
		}

		const contentLength = Number.parseInt(match[1], 10);
		const bodyStart = headerEnd + 4;
		const bodyEnd = bodyStart + contentLength;

		if (buffer.length < bodyEnd) break;

		const body = buffer.substring(bodyStart, bodyEnd);
		buffer = buffer.substring(bodyEnd);

		try {
			messages.push(JSON.parse(body) as DAPMessage);
		} catch {
			// Skip malformed
		}
	}

	return { messages, remaining: buffer };
}

/**
 * pi-ci — Headless orchestrator.
 *
 * Ties together exit codes, answer injection, idle detection, and JSONL
 * streaming into a single execution loop.
 */

import type { ExitCode, CIEvent, CIOptions } from "../types.ts";
import { EXIT_CODES } from "../types.ts";
import { resolveExitCode } from "./exit-codes.ts";
import { matchAnswer, type AnswerEntry } from "./answer-injector.ts";
import { IdleDetector } from "./idle-detector.ts";
import { CIEventCollector, writeCIEvent } from "./jsonl-stream.ts";
import type { Writable } from "node:stream";

export interface OrchestratorResult {
  exitCode: ExitCode;
  events: CIEvent[];
  durationMs: number;
}

export interface OrchestratorHooks {
  /** Called for each step of execution. Return a status string to signal completion. */
  executeStep: (
    prompt: string,
    injectAnswer: (question: string) => string | undefined,
  ) => Promise<StepResult>;
  /** Optional writable for JSONL streaming. */
  outputStream?: Writable;
}

export interface StepResult {
  status: string;
  edits?: { file: string; lines_added: number; lines_removed: number }[];
  tests?: { command: string; passed: number; failed: number }[];
  cost?: { tokens: *** input: number; output: number }; cost_usd: number };
}

const RESTART_CONFIG = {
  baseDelayMs: 5_000,
  maxDelayMs: 30_000,
  backoffMultiplier: 2,
};

export class HeadlessOrchestrator {
  private readonly collector = new CIEventCollector();
  private readonly answers: AnswerEntry[];
  private readonly idleTimeoutMs: number;
  private readonly maxRetries: number;
  private readonly hooks: OrchestratorHooks;

  constructor(
    answers: AnswerEntry[],
    options: CIOptions,
    hooks: OrchestratorHooks,
  ) {
    this.answers = answers;
    this.idleTimeoutMs = options.idleTimeoutMs ?? 15_000;
    this.maxRetries = options.maxRetries ?? 3;
    this.hooks = hooks;
  }

  /**
   * Run the orchestrator loop.
   *
   * 1. Emit ci_start
   * 2. Execute steps via the hook, checking for answer injection
   * 3. On idle timeout → retry with exponential backoff
   * 4. Emit ci_end with the resolved exit code
   */
  async run(prompt: string, mode: "single" | "plan"): Promise<OrchestratorResult> {
    const startTime = Date.now();

    const startEvent: CIEvent = {
      type: "ci_start",
      timestamp: new Date().toISOString(),
      task: prompt,
      mode,
    };
    this.emit(startEvent);

    let lastExitCode: ExitCode = EXIT_CODES.ERROR;
    let retries = 0;

    while (retries <= this.maxRetries) {
      const result = await this.runAttempt(prompt);
      lastExitCode = result;

      if (lastExitCode === EXIT_CODES.SUCCESS) break;
      if (lastExitCode === EXIT_CODES.BLOCKED || lastExitCode === EXIT_CODES.CANCELLED) break;

      // Retry on error/timeout
      retries++;
      if (retries <= this.maxRetries) {
        const delay = Math.min(
          RESTART_CONFIG.baseDelayMs *
            Math.pow(RESTART_CONFIG.backoffMultiplier, retries - 1),
          RESTART_CONFIG.maxDelayMs,
        );
        await sleep(delay);
      }
    }

    const durationMs = Date.now() - startTime;
    const endEvent: CIEvent = {
      type: "ci_end",
      timestamp: new Date().toISOString(),
      exit_code: lastExitCode,
      duration_ms: durationMs,
    };
    this.emit(endEvent);

    return {
      exitCode: lastExitCode,
      events: this.collector.all(),
      durationMs,
    };
  }

  /**
   * Single attempt: run with idle detection.
   */
  private async runAttempt(prompt: string): Promise<ExitCode> {
    return new Promise<ExitCode>((resolve) => {
      let settled = false;

      const idle = new IdleDetector({
        idleTimeoutMs: this.idleTimeoutMs,
        onTimeout: () => {
          if (!settled) {
            settled = true;
            resolve(EXIT_CODES.TIMEOUT);
          }
        },
      });

      const injectAnswer = (question: string): string | undefined => {
        idle.reset();
        return matchAnswer(this.answers, question);
      };

      idle.start();

      this.hooks
        .executeStep(prompt, injectAnswer)
        .then((stepResult) => {
          if (!settled) {
            settled = true;
            idle.stop();

            // Emit detail events
            if (stepResult.edits) {
              for (const edit of stepResult.edits) {
                this.emit({
                  type: "ci_edit",
                  timestamp: new Date().toISOString(),
                  file: edit.file,
                  lines_added: edit.lines_added,
                  lines_removed: edit.lines_removed,
                });
              }
            }
            if (stepResult.tests) {
              for (const t of stepResult.tests) {
                this.emit({
                  type: "ci_test",
                  timestamp: new Date().toISOString(),
                  command: t.command,
                  passed: t.passed,
                  failed: t.failed,
                });
              }
            }
            if (stepResult.cost) {
              this.emit({
                type: "ci_cost",
                timestamp: new Date().toISOString(),
                tokens: ***,
                cost_usd: stepResult.cost.cost_usd,
              });
            }

            resolve(resolveExitCode(stepResult.status));
          }
        })
        .catch(() => {
          if (!settled) {
            settled = true;
            idle.stop();
            resolve(EXIT_CODES.ERROR);
          }
        });
    });
  }

  private emit(event: CIEvent): void {
    this.collector.emit(event);
    if (this.hooks.outputStream) {
      writeCIEvent(this.hooks.outputStream, event);
    }
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

import type { LSPClientPool } from "../client/manager.ts";
import { BufferTracker } from "./buffer-tracker.ts";
import { pathToUri } from "../client/client.ts";

const tracker = new BufferTracker();

export function getBufferTracker(): BufferTracker {
	return tracker;
}

export async function syncContent(pool: LSPClientPool, filePath: string, content: string): Promise<void> {
	const fileUri = pathToUri(filePath);
	const client = await pool.getClientForFile(filePath);
	if (!client) return;

	if (!tracker.has(fileUri)) {
		// First sync: didOpen
		const doc = tracker.set(fileUri, content);
		client.sendNotification("textDocument/didOpen", {
			textDocument: {
				uri: fileUri,
				languageId: languageIdFromPath(filePath),
				version: doc.version,
				text: content,
			},
		});
	} else {
		// Subsequent sync: didChange with full content
		const doc = tracker.set(fileUri, content);
		client.sendNotification("textDocument/didChange", {
			textDocument: { uri: fileUri, version: doc.version },
			contentChanges: [{ text: content }],
		});
	}
}

export function closeDocument(pool: LSPClientPool, filePath: string): void {
	const fileUri = pathToUri(filePath);
	const client = pool.getClientForFileSync(filePath);
	if (!client) return;

	if (tracker.has(fileUri)) {
		client.sendNotification("textDocument/didClose", {
			textDocument: { uri: fileUri },
		});
		tracker.delete(fileUri);
	}
}

function languageIdFromPath(filePath: string): string {
	const ext = filePath.split(".").pop() ?? "";
	const map: Record<string, string> = {
		ts: "typescript",
		tsx: "typescriptreact",
		js: "javascript",
		jsx: "javascriptreact",
		py: "python",
		rs: "rust",
		go: "go",
	};
	return map[ext] ?? ext;
}

import type { LSPClient } from "../client/client.ts";
import type { Diagnostic as LspDiagnostic } from "../types.ts";

export interface DiagnosticsParams {
	file?: string;
}

export interface DiagnosticResult {
	diagnostics: Array<{
		file: string;
		line: number;
		column: number;
		severity: number;
		message: string;
		source?: string;
	}>;
}

export function collectDiagnostics(client: LSPClient, fileUri?: string): DiagnosticResult {
	const allDiags = client.getAllDiagnostics();
	const diagnostics: DiagnosticResult["diagnostics"] = [];

	if (fileUri) {
		const diags = allDiags.get(fileUri) ?? [];
		for (const d of diags) {
			diagnostics.push({
				file: fileUri.replace(/^file:\/\//, ""),
				line: d.range.start.line + 1,
				column: d.range.start.character + 1,
				severity: d.severity ?? 1,
				message: d.message,
				source: d.source,
			});
		}
	} else {
		for (const [uri, diags] of allDiags) {
			for (const d of diags) {
				diagnostics.push({
					file: uri.replace(/^file:\/\//, ""),
					line: d.range.start.line + 1,
					column: d.range.start.character + 1,
					severity: d.severity ?? 1,
					message: d.message,
					source: d.source,
				});
			}
		}
	}

	return { diagnostics };
}

export async function waitForDiagnostics(client: LSPClient, fileUri: string, timeoutMs = 5000): Promise<DiagnosticResult> {
	const startTime = Date.now();
	const existing = client.getDiagnostics(fileUri);
	if (existing.length > 0) {
		return collectDiagnostics(client, fileUri);
	}

	// Poll until diagnostics arrive or timeout
	while (Date.now() - startTime < timeoutMs) {
		await new Promise((resolve) => setTimeout(resolve, 200));
		const current = client.getDiagnostics(fileUri);
		if (current.length > 0) {
			return collectDiagnostics(client, fileUri);
		}
	}

	return collectDiagnostics(client, fileUri);
}

import type Database from "better-sqlite3";
import { recallMemories, wrapInAntiFeedbackTags } from "../memory/recall.ts";
import { logEvent } from "../store/events.ts";

export interface CompactionContext {
	taskDescription: string;
	compactionEntry?: string;
}

/**
 * Handle the preCompactionContext hook.
 * When Pi compacts the context window, recall relevant memories to preserve
 * important information that was shed.
 */
export function handleCompaction(
	db: Database.Database,
	sessionId: string,
	context: CompactionContext,
	budget: number = 2048,
): string {
	// Log the compaction event
	logEvent(db, sessionId, "compaction", {
		taskDescription: context.taskDescription,
		timestamp: new Date().toISOString(),
	});

	// Recall relevant memories for the current task
	const result = recallMemories(db, context.taskDescription, budget);

	// Wrap in anti-feedback tags and return
	return wrapInAntiFeedbackTags(result.content);
}

import type Database from "better-sqlite3";
import { getSessionEvents, getRecentEvents } from "../store/events.ts";

export interface ResumeContext {
	lastFiles: string[];
	lastError: string | null;
	lastTask: string | null;
	status: string;
	sessionId: string | null;
}

/**
 * Build a resume context from the most recent session's events.
 */
export function buildResumeContext(db: Database.Database): ResumeContext | null {
	// Find the most recent session
	const recentEvents = getRecentEvents(db, 100);
	if (recentEvents.length === 0) return null;

	// Group by session
	const sessionMap = new Map<string, typeof recentEvents>();
	for (const event of recentEvents) {
		const sid = event.session_id ?? "__unknown__";
		if (!sessionMap.has(sid)) sessionMap.set(sid, []);
		sessionMap.get(sid)!.push(event);
	}

	// Find the most recent session (by its latest event)
	let latestSessionId: string | null = null;
	let latestTimestamp = "";
	for (const [sid, events] of sessionMap) {
		const lastEvent = events[0]; // already sorted DESC
		if (lastEvent && lastEvent.timestamp > latestTimestamp) {
			latestTimestamp = lastEvent.timestamp;
			latestSessionId = sid;
		}
	}

	if (!latestSessionId || latestSessionId === "__unknown__") return null;

	return buildSessionResumeContext(db, latestSessionId);
}

/**
 * Build resume context for a specific session.
 */
export function buildSessionResumeContext(db: Database.Database, sessionId: string): ResumeContext | null {
	const events = getSessionEvents(db, sessionId);
	if (events.length === 0) return null;

	const files: string[] = [];
	let lastError: string | null = null;
	let lastTask: string | null = null;

	for (const event of events) {
		try {
			const data = JSON.parse(event.data) as Record<string, unknown>;
			if (event.type === "file_edit" && typeof data.file === "string") {
				if (!files.includes(data.file)) files.push(data.file);
			}
			if (event.type === "error" && typeof data.errorMessage === "string") {
				lastError = data.errorMessage;
			}
			if (event.type === "user_decision" && typeof data.message_summary === "string") {
				lastTask = data.message_summary;
			}
		} catch { /* skip malformed data */ }
	}

	// Determine status
	const hasErrors = events.some((e) => e.type === "error");
	const status = hasErrors ? "had errors" : "completed successfully";

	return {
		lastFiles: files,
		lastError,
		lastTask,
		status,
		sessionId,
	};
}

/**
 * Format a resume context as a human-readable prompt.
 */
export function formatResumeContext(context: ResumeContext, maxBytes: number = 1024): string {
	const lines: string[] = [
		"Previous session context:",
		`- Last working on: "${context.lastTask ?? "unknown task"}"`,
	];
	if (context.lastFiles.length > 0) {
		lines.push(`- Files modified: ${context.lastFiles.join(", ")}`);
	}
	if (context.lastError) {
		lines.push(`- Last error: "${context.lastError}"`);
	}
	lines.push(`- Status: ${context.status}`);
	lines.push("Continue where you left off?");

	const text = lines.join("\n");
	const encoded = new TextEncoder().encode(text);
	if (encoded.length <= maxBytes) return text;
	return new TextDecoder().decode(encoded.slice(0, maxBytes));
}

import type { ExtensionAPI, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import type { Intensity } from "../config.ts";
import type { SessionCost } from "../cost/tracker.ts";
import { formatDetailedCost, formatWidgetString, formatWidgetData } from "../cost/widget.ts";

interface SessionState {
	intensity: Intensity;
	budgetState: string;
	config: { enabled: boolean; filters: { enabled: boolean; profiles: Record<string, string[]>; defaultProfile: string[] } };
	totalBytesIn: number;
	totalBytesOut: number;
	costTracker: {
		getSessionCost: (fn: (model: string, usage: { inputTokens: ***; outputTokens: ***; cacheReadTokens?: number; cacheWriteTokens?: number }) => number) => SessionCost;
	};
	pricing: { calculateCost: (model: string, usage: { inputTokens: ***; outputTokens: ***; cacheReadTokens?: number; cacheWriteTokens?: number }) => number };
}

export interface SmartCommandDeps {
	getState: () => SessionState;
	getCostSummary: () => SessionCost;
	setIntensity: (intensity: Intensity) => void;
}

export function registerSmartCommands(pi: ExtensionAPI, deps: SmartCommandDeps): void {
	const { getState, getCostSummary, setIntensity } = deps;

	pi.registerCommand("smart", {
		description: "pi-smart status and configuration",
			handler: async (args: string, _ctx: ExtensionCommandContext): Promise<void> => {
			const state = getState();
			const cost = getCostSummary();
			const arg = args?.trim().split(/\s+/)[0];

			if (arg === "cost") {
				console.log(formatDetailedCost(cost));
				return;
			}

			if (arg === "filters") {
				const profiles = Object.entries(state.config.filters.profiles)
					.map(([key, filters]) => `  ${key}: [${filters.join(", ")}]`)
					.join("\n");
				console.log([
					"pi-smart Filter Profiles:",
					profiles,
					`  default: [${state.config.filters.defaultProfile.join(", ")}]`,
				].join("\n"));
				return;
			}

			if (arg === "terse" || arg === "normal" || arg === "verbose") {
				setIntensity(arg);
				console.log(`pi-smart intensity set to ${arg}`);
				return;
			}

			// Default: show status dashboard
			const data = formatWidgetData(cost, state.intensity, state.totalBytesIn - state.totalBytesOut, state.totalBytesIn);
			console.log([
				"pi-smart Status:",
				`  Output filtering: ${state.config.filters.enabled ? "ON" : "OFF"} (saved ${state.totalBytesIn > 0 ? Math.round((state.totalBytesIn - state.totalBytesOut) / 1024) : 0}KB this session)`,
				`  Response compression: ${state.intensity}`,
				`  Context budget: ${state.budgetState}`,
				`  Session cost: ${data.totalCost} (${data.totalTokens} tokens)`,
				"",
				formatWidgetString(data),
				"",
				"Usage: /smart terse|normal|verbose | /smart cost | /smart filters",
			].join("\n"));
		},
	});
}

