describe("sandbox", () => {
	it("executes JavaScript and returns stdout", async () => {
		const result = await executeInSandbox({
			language: "javascript",
			code: "console.log('hello from sandbox');",
			cwd: process.cwd(),
			timeout: 5000,
		});
		assert.equal(result.exitCode, 0);
		assert.ok(result.stdout.includes("hello from sandbox"));
	});

	it("captures stderr on error", async () => {
		const result = await executeInSandbox({
			language: "javascript",
			code: "throw new Error('test error');",
			cwd: process.cwd(),
			timeout: 5000,
		});
		assert.notEqual(result.exitCode, 0);
		assert.ok(result.stderr.includes("test error"));
	});

	it("returns error for unsupported language", async () => {
		const result = await executeInSandbox({
			language: "rust",
			code: "fn main() {}",
			cwd: process.cwd(),
		});
		assert.ok(result.stderr.includes("Unsupported language"));
	});

	it("times out for long-running code", async () => {
		const result = await executeInSandbox({
			language: "javascript",
			code: "while(true) {}",
			cwd: process.cwd(),
			timeout: 1000,
		});
		assert.ok(result.timedOut || result.exitCode !== 0);
	});

	it("truncates large output", async () => {
		const result = await executeInSandbox({
			language: "javascript",
			code: "console.log('x'.repeat(10000));",
			cwd: process.cwd(),
			timeout: 5000,
			maxOutputBytes: 100,
		});
		assert.ok(result.stdout.includes("truncated"));
		assert.ok(result.bytesProcessed > result.bytesReturned);
	});

	it("tracks bytes processed and returned", async () => {
		const result = await executeInSandbox({
			language: "javascript",
			code: "console.log('hello');",
			cwd: process.cwd(),
			timeout: 5000,
		});
		assert.ok(result.bytesProcessed > 0);
		assert.ok(result.bytesReturned > 0);
	});
});

import assert from "node:assert/strict";
import test, { describe } from "node:test";
import { ReviewOrchestrator } from "../../src/review/orchestrator.ts";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

describe("ReviewOrchestrator", () => {
	test("constructor loads config without error", () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-orch-"));
		try {
			const orchestrator = new ReviewOrchestrator(dir);
			assert.ok(orchestrator);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});

	test("resolvePerspectives defaults to enabled perspectives", () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-orch-"));
		try {
			const orchestrator = new ReviewOrchestrator(dir);
			// Access private method via cast
			const report = orchestrator.generateFormattedReport([], {
				format: "markdown",
				groupBy: "file",
				includeSuggestions: true,
			});
			assert.ok(report);
			assert.equal(report.findings.length, 0);
		} finally {
			fs.rmSync(dir, { recursive: true });
		}
	});

	test("reviewDiff returns a report structure", async () => {
		const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-review-orch-"));
		try {
			// Initialize a git repo
			fs.writeFileSync(path.join(dir, "test.txt"), "hello\n");
			const { execSync } = await import("node:child_process");
			execSync("git init", { cwd: dir });
			execSync("git config user.email test@test.com", { cwd: dir });
			execSync("git config user.name Test", { cwd: dir });
			execSync("git add .", { cwd: dir });
			execSync("git commit -m initial", { cwd: dir });

			// Make a change
			fs.writeFileSync(path.join(dir, "test.txt"), "hello world\n");
			execSync("git add .", { cwd: dir });
			execSync("git commit -m change", { cwd: dir });

			const orchestrator = new ReviewOrchestrator(dir);
			const report = await orchestrator.reviewDiff(dir, { base: "HEAD~1", head: "HEAD" });

			assert.ok(report);
			assert.ok(report.timestamp);
			assert.ok(report.perspectives);
			assert.ok(report.summary);
			assert.ok(Array.isArray(report.findings));
		} finally {
			fs.rmSync(dir, { recursive: true, force: true });
		}
	});
});

import assert from "node:assert/strict";
import test, { describe } from "node:test";
import { detectAmbiguity, mentionsFiles, looksLikeCodingTask } from "../../src/clarify/ambiguity.ts";

describe("mentionsFiles", () => {
	test("detects backtick-quoted files", () => {
		assert.equal(mentionsFiles("fix the bug in `src/foo.ts`"), 1);
	});

	test("detects path-like references", () => {
		assert.equal(mentionsFiles("update src/utils/helper.ts"), 1);
		assert.equal(mentionsFiles("fix test/unit/config.test.ts"), 1);
	});

	test("returns 0 for no files", () => {
		assert.equal(mentionsFiles("fix the bug"), 0);
	});
});

describe("looksLikeCodingTask", () => {
	test("detects fix/implement/add", () => {
		assert.equal(looksLikeCodingTask("fix the login bug"), true);
		assert.equal(looksLikeCodingTask("implement the feature"), true);
		assert.equal(looksLikeCodingTask("add a new field"), true);
	});

	test("returns false for questions", () => {
		assert.equal(looksLikeCodingTask("what is the meaning of life?"), false);
	});
});

describe("detectAmbiguity", () => {
	test("detects vague_action", () => {
		const signals = detectAmbiguity("improve the performance");
		assert.ok(signals.some((s) => s.type === "vague_action"));
		// no_files not triggered: "improve" matches vague_action but not looksLikeCodingTask
	});

	test("detects architecture_change", () => {
		const signals = detectAmbiguity("rewrite the authentication module");
		assert.ok(signals.some((s) => s.type === "architecture_change"));
	});

	test("detects security_sensitive", () => {
		const signals = detectAmbiguity("fix the auth token handling");
		assert.ok(signals.some((s) => s.type === "security_sensitive"));
	});

	test("detects ambiguous_reference in short messages", () => {
		const signals = detectAmbiguity("fix it");
		assert.ok(signals.some((s) => s.type === "ambiguous_reference"));
	});

	test("does not detect ambiguous_reference in long messages", () => {
		const signals = detectAmbiguity("fix it in the login page by updating the validation logic and adding proper error handling for all the edge cases we discussed yesterday");
		assert.ok(!signals.some((s) => s.type === "ambiguous_reference"));
	});

	test("detects unclear_scope", () => {
		const signals = detectAmbiguity("refactor everything");
		assert.ok(signals.some((s) => s.type === "unclear_scope"));
	});

	test("returns empty for clear specific tasks", () => {
		const signals = detectAmbiguity("change the greeting in `src/hello.ts` from 'hi' to 'hello'");
		assert.equal(signals.length, 0);
	});

	test("detects multiple signals", () => {
		const signals = detectAmbiguity("improve the auth system completely");
		assert.ok(signals.length >= 2);
	});
});

import type Database from "better-sqlite3";
import { logEvent } from "../store/events.ts";

export interface SessionTracker {
	trackEdit(file: string, turn: number): void;
	trackError(tool: string, errorMessage: string, turn: number): void;
	trackDecision(message: string, turn: number): void;
	trackCommandSuccess(command: string, outputSummary: string, turn: number): void;
	trackGitOp(gitOp: string, turn: number): void;
}

/**
 * Create a session tracker that logs events to the events table.
 */
export function createSessionTracker(
	db: Database.Database,
	sessionId: string,
): SessionTracker {
	return {
		trackEdit(file: string, turn: number): void {
			logEvent(db, sessionId, "file_edit", { file, turn });
		},
		trackError(tool: string, errorMessage: string, turn: number): void {
			logEvent(db, sessionId, "error", { tool, errorMessage, turn });
		},
		trackDecision(message: string, turn: number): void {
			logEvent(db, sessionId, "user_decision", { message_summary: message.slice(0, 500), turn });
		},
		trackCommandSuccess(command: string, outputSummary: string, turn: number): void {
			logEvent(db, sessionId, "command_success", { command, output_summary: outputSummary.slice(0, 500), turn });
		},
		trackGitOp(gitOp: string, turn: number): void {
			logEvent(db, sessionId, "git_operation", { gitOp, turn });
		},
	};
}

import type { PipelineState, TaskContext, GateResult } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";
import { runGates, GATE_CHECKS } from "../verify/gates.ts";
import { checkEvidenceCompleteness } from "../verify/evidence.ts";
import { checkStopTheLine, formatStopTheLine } from "../verify/stop-the-line.ts";
import { matchAntiRationalization } from "../verify/anti-rationalization.ts";

export interface VerifyCommandResult {
	message: string;
	state: PipelineState;
	results?: GateResult[];
}

/**
 * Handle /verify: run verification gates.
 */
export function handleVerify(
	state: PipelineState,
	ctx: TaskContext,
	config: PipelineExtensionConfig,
): VerifyCommandResult {
	if (!config.verification.enabled) {
		return { message: "Verification gates are disabled.", state };
	}

	const gateIds = [...config.verification.gates];
	if (config.verification.tddGate && !gateIds.includes("tdd")) {
		gateIds.push("tdd");
	}

	const results = runGates(ctx, gateIds);

	// Check stop-the-line
	if (config.verification.stopTheLine) {
		const stopResult = checkStopTheLine(results, config.verification.blockingGates);
		if (stopResult.blocked) {
			return {
				message: formatStopTheLine(stopResult) +
					"\n\nGate results:\n" +
					results.map((r) => `  ${r.passed ? "✅" : "❌"} ${r.gateId}: ${r.message}`).join("\n"),
				state,
				results,
			};
		}
	}

	const passed = results.every((r) => r.passed);
	const summary = results.map((r) => `  ${r.passed ? "✅" : "❌"} ${r.gateId}: ${r.message}`).join("\n");

	return {
		message: passed ? `All gates passed!\n${summary}` : `Some gates failed:\n${summary}`,
		state,
		results,
	};
}

/**
 * Handle /verify evidence: show evidence checklist.
 */
export function handleVerifyEvidence(
	state: PipelineState,
	ctx: TaskContext,
): VerifyCommandResult {
	const evidence = checkEvidenceCompleteness(ctx);

	// Check for anti-rationalization in output
	const antiRat = matchAntiRationalization(ctx.assistantOutput);

	const parts: string[] = [];
	parts.push("Evidence Checklist:");
	if (evidence.missing.length === 0) {
		parts.push("  ✅ All evidence provided");
	} else {
		for (const item of evidence.missing) {
			parts.push(`  ❌ ${item}`);
		}
	}

	if (antiRat) {
		parts.push("");
		parts.push(`⚠️ Anti-rationalization detected:`);
		parts.push(`  Excuse: "${antiRat.excuse}"`);
		parts.push(`  Reality: "${antiRat.reality}"`);
	}

	return {
		message: parts.join("\n"),
		state,
	};
}

import { spawn } from "node:child_process";

export interface GitDiffOptions {
	base?: string;
	head?: string;
	cwd: string;
	maxFiles?: number;
}

export async function extractDiff(options: GitDiffOptions): Promise<string> {
	const { cwd, base, head, maxFiles = 20 } = options;

	const args = ["diff", "--unified=5"];
	if (base && head) {
		args.push(`${base}...${head}`);
	} else if (base) {
		args.push(base);
	} else {
		// Default: staged + unstaged changes vs HEAD
		args.push("HEAD");
	}

	const result = await runGit(args, cwd);

	if (result.exitCode !== 0 && !result.stdout) {
		throw new Error(`git diff failed (exit ${result.exitCode}): ${result.stderr}`);
	}

	// Limit files if needed
	if (maxFiles > 0) {
		return limitFiles(result.stdout, maxFiles);
	}

	return result.stdout;
}

export async function extractFileDiff(cwd: string, file: string, base?: string): Promise<string> {
	const args = ["diff", "--unified=5"];
	if (base) {
		args.push(base);
	} else {
		args.push("HEAD");
	}
	args.push("--", file);

	const result = await runGit(args, cwd);
	return result.stdout;
}

function limitFiles(diff: string, maxFiles: number): string {
	const files: string[] = [];
	const lines = diff.split("\n");
	const output: string[] = [];
	let currentFileOutput: string[] = [];
	let inFile = false;

	for (const line of lines) {
		if (line.startsWith("diff --git")) {
			if (inFile && files.length < maxFiles) {
				output.push(...currentFileOutput);
			}
			if (files.length >= maxFiles) {
				output.push(`\n... (truncated: showing first ${maxFiles} files)`);
				return output.join("\n");
			}
			const match = line.match(/^diff --git a\/(.+?) b\/(.+)$/);
			if (match) {
				files.push(match[2]!);
			}
			currentFileOutput = [line];
			inFile = true;
		} else if (inFile) {
			currentFileOutput.push(line);
		}
	}

	if (inFile && files.length <= maxFiles) {
		output.push(...currentFileOutput);
	}

	return output.join("\n");
}

function runGit(args: string[], cwd: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
	return new Promise((resolve) => {
		const proc = spawn("git", args, { cwd, stdio: ["ignore", "pipe", "pipe"] });
		const stdoutChunks: Buffer[] = [];
		const stderrChunks: Buffer[] = [];

		proc.stdout.on("data", (chunk: Buffer) => stdoutChunks.push(chunk));
		proc.stderr.on("data", (chunk: Buffer) => stderrChunks.push(chunk));

		proc.on("close", (code) => {
			resolve({
				stdout: Buffer.concat(stdoutChunks).toString("utf-8"),
				stderr: Buffer.concat(stderrChunks).toString("utf-8"),
				exitCode: code ?? 0,
			});
		});

		proc.on("error", (err) => {
			resolve({ stdout: "", stderr: err.message, exitCode: 1 });
		});
	});
}
